/**
 * Self-contained reducer test for the certified allocation kernel.
 *
 * Run:
 *   pnpm run gnode -- run open-source/gnosis/src/__tests__/certified-allocation-kernel.test.ts
 */

import assert from 'node:assert';
import {
  CERTIFIED_ALLOCATION_KERNEL_THEOREM_IDS,
  calibrationObservationConserved,
  canonicalCandidateId,
  deriveCertifiedAllocationKernel,
  type CertifiedAllocationKernelInput,
} from '../certified-allocation-kernel';

const BASE_INPUT: CertifiedAllocationKernelInput = {
  generatedAt: '2026-04-10T00:00:00.000Z',
  source: 'test-suite',
  plan: {
    pointIds: ['top-left', 'center'],
    samplesPerPoint: 2,
    maxAttemptsPerPoint: 4,
  },
  points: [
    {
      pointId: 'top-left',
      accepted: 2,
      rejected: 0,
      observed: 2,
    },
    {
      pointId: 'center',
      accepted: 2,
      rejected: 1,
      observed: 3,
    },
  ],
  modelSolved: true,
  frame: {
    gazePoint: { x: 510, y: 510 },
    zone: 'unavailable',
    confidenceScore: 87,
    confidenceFloor: 60,
  },
  candidateIds: [12, 5, 9],
  budget: {
    deadlineMs: 5,
    elapsedMs: 3,
  },
};

const deterministicA = deriveCertifiedAllocationKernel(BASE_INPUT);
const deterministicB = deriveCertifiedAllocationKernel({
  ...BASE_INPUT,
  candidateIds: [...BASE_INPUT.candidateIds].reverse(),
});

assert.deepStrictEqual(deterministicA, deterministicB);
assert.strictEqual(deterministicA.generatedAt, '2026-04-10T00:00:00.000Z');
assert.strictEqual(deterministicA.source, 'test-suite');
assert.strictEqual(deterministicA.observationZone, 'center');
assert.strictEqual(deterministicA.inputZone, 'unavailable');
assert.strictEqual(deterministicA.inputZoneConsistent, false);
assert.deepStrictEqual(deterministicA.decision, {
  kind: 'allocate',
  candidateId: 5,
});
assert.strictEqual(deterministicA.aggregate.requiredSamples, 4);
assert.strictEqual(deterministicA.aggregate.acceptedSamples, 4);
assert.strictEqual(deterministicA.aggregate.rejectedSamples, 1);
assert.strictEqual(deterministicA.aggregate.observedSamples, 5);
assert.strictEqual(deterministicA.aggregate.deficit, 0);
assert.strictEqual(deterministicA.aggregate.conserved, true);
assert.strictEqual(deterministicA.aggregate.terminated, true);
assert.strictEqual(deterministicA.aggregate.ready, true);
assert.strictEqual(deterministicA.aggregate.nextPointId, null);
assert.strictEqual(deterministicA.aggregate.confidenceFloorSatisfied, true);
assert.strictEqual(deterministicA.aggregate.withinBudget, true);

for (const theoremId of CERTIFIED_ALLOCATION_KERNEL_THEOREM_IDS) {
  assert.ok(deterministicA.theoremIds.includes(theoremId));
}

assert.strictEqual(canonicalCandidateId([11, 4, 19]), 4);
assert.strictEqual(canonicalCandidateId([]), null);
assert.strictEqual(
  calibrationObservationConserved(BASE_INPUT.points),
  true
);
assert.strictEqual(
  calibrationObservationConserved([
    {
      pointId: 'bad',
      accepted: 1,
      rejected: 0,
      observed: 3,
    },
  ]),
  false
);

const deadlineFailure = deriveCertifiedAllocationKernel({
  ...BASE_INPUT,
  budget: {
    deadlineMs: 2,
    elapsedMs: 4,
  },
});
assert.deepStrictEqual(deadlineFailure.decision, {
  kind: 'safe-state',
  reason: 'deadline-exceeded',
});
assert.strictEqual(deadlineFailure.aggregate.withinBudget, false);

const notCalibrated = deriveCertifiedAllocationKernel({
  ...BASE_INPUT,
  points: [
    {
      pointId: 'top-left',
      accepted: 1,
      rejected: 1,
      observed: 2,
    },
    {
      pointId: 'center',
      accepted: 0,
      rejected: 0,
      observed: 0,
    },
  ],
});
assert.deepStrictEqual(notCalibrated.decision, {
  kind: 'safe-state',
  reason: 'not-calibrated',
});
assert.strictEqual(notCalibrated.aggregate.ready, false);
assert.strictEqual(notCalibrated.aggregate.nextPointId, 'top-left');
assert.strictEqual(notCalibrated.aggregate.deficit, 3);

const unavailableObservation = deriveCertifiedAllocationKernel({
  ...BASE_INPUT,
  frame: {
    gazePoint: null,
    zone: 'center',
    confidenceScore: 10,
    confidenceFloor: 60,
  },
});
assert.deepStrictEqual(unavailableObservation.decision, {
  kind: 'safe-state',
  reason: 'observation-unavailable',
});
assert.strictEqual(unavailableObservation.observationZone, 'unavailable');
assert.strictEqual(unavailableObservation.aggregate.confidenceFloorSatisfied, true);

const noCandidates = deriveCertifiedAllocationKernel({
  ...BASE_INPUT,
  candidateIds: [],
});
assert.deepStrictEqual(noCandidates.decision, {
  kind: 'safe-state',
  reason: 'no-candidates',
});

console.log('certified-allocation-kernel: all tests passed');
